export function Skills() {
  const [activeCategory, setActiveCategory] = useState('frontend');

  const currentCategory = skillCategories.find((c) => c.id === activeCategory)!;

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.08, delayChildren: 0.1 },
    },
  };

  const easing = [0.25, 0.46, 0.45, 0.94] as [number, number, number, number];

  const itemVariants = {
    hidden: { opacity: 0, y: 30, scale: 0.95 },
    visible: {
      opacity: 1,
      y: 0,
      scale: 1,
      transition: { duration: 0.5, ease: easing },
    },
  };

  return (
    <section id="skills" className="relative section-padding overflow-hidden">
      {/* Background */}
      <div className="absolute inset-0" style={{ background: 'radial-gradient(ellipse 60% 40% at 50% 80%, rgba(124, 58, 237, 0.06) 0%, transparent 60%)' }} />

      <div className="relative max-w-5xl mx-auto px-4">
        <SectionHeading
          title="Tech Stack"
        />

        {/* Category tabs */}
        <div className="flex justify-center mb-12">
          <div className="flex gap-2 p-1.5 rounded-2xl"
            style={{ background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.06)' }}>
            {skillCategories.map((cat) => (
              <button
                key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                className="relative px-6 py-2.5 rounded-xl text-sm font-medium transition-all duration-300 cursor-none"
                style={{ color: activeCategory === cat.id ? '#fff' : '#71717A' }}
              >
                {activeCategory === cat.id && (
                  <motion.span
                    layoutId="skill-tab-active"
                    className="absolute inset-0 rounded-xl"
                    style={{ background: `${cat.color}20`, border: `1px solid ${cat.color}40` }}
                    transition={{ type: 'spring', duration: 0.4 }}
                  />
                )}
                <span className="relative z-10">{cat.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Skills grid */}
        <AnimatePresence mode="wait">
          <motion.div
            key={activeCategory}
            variants={containerVariants}
            initial="hidden"
            animate="visible"
            exit={{ opacity: 0, y: -10, transition: { duration: 0.2 } }}
            className="flex flex-wrap justify-center gap-5"
          >
            {currentCategory.skills.map((skill) => (
              <motion.div
                key={skill.name}
                variants={itemVariants}
                whileHover={{ y: -8, scale: 1.02 }}
                className="group relative p-6 rounded-2xl flex flex-col items-center gap-3 cursor-none w-36"
                style={{
                  background: 'rgba(24, 24, 27, 0.6)',
                  backdropFilter: 'blur(20px)',
                  border: '1px solid rgba(255,255,255,0.07)',
                  boxShadow: '0 4px 20px rgba(0,0,0,0.2)',
                  transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                }}
                onMouseEnter={(e) => {
                  const el = e.currentTarget as HTMLElement;
                  el.style.borderColor = `${skill.color}40`;
                  el.style.boxShadow = `0 4px 30px rgba(0,0,0,0.2), 0 0 30px ${skill.color}15`;
                  el.style.background = skill.bg;
                }}
                onMouseLeave={(e) => {
                  const el = e.currentTarget as HTMLElement;
                  el.style.borderColor = 'rgba(255,255,255,0.07)';
                  el.style.boxShadow = '0 4px 20px rgba(0,0,0,0.2)';
                  el.style.background = 'rgba(24, 24, 27, 0.6)';
                }}
              >
                {/* Gradient border on hover */}
                <div className="absolute inset-0 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none"
                  style={{ background: `linear-gradient(135deg, ${skill.color}05, transparent)` }} />

                {/* Icon */}
                <div className="relative">
                  <div className="absolute inset-0 rounded-full blur-lg opacity-0 group-hover:opacity-60 transition-opacity"
                    style={{ background: skill.color }} />
                  {skill.icon}
                </div>

                {/* Name */}
                <span className="text-sm font-semibold text-center" style={{ color: '#E4E4E7' }}>
                  {skill.name}
                </span>

                {/* Color dot */}
                <div className="w-1.5 h-1.5 rounded-full opacity-60" style={{ background: skill.color }} />
              </motion.div>
            ))}
          </motion.div>
        </AnimatePresence>
      </div>
    </section>
  );
}
